-- Plan comptable simplifié (147 comptes) + toggle par entreprise.
-- Le plan simplifié contient en plus : categorie (regroupement visuel),
-- mots_cles (aide à la recherche), exemples (doc utilisateur), sens (D/C, utilisé
-- pour filtrer l'autocomplete selon le type débit/crédit de la ligne en cours
-- de saisie) et pcg_parent (lien indicatif vers le compte PCG général).
--
-- L'entreprise peut basculer entre le plan général et le simplifié via la
-- colonne plan_comptable ('general' | 'simplifie'). Le simplifié est le défaut.

CREATE TABLE plan_comptable_simplifie (
    numero VARCHAR(10) PRIMARY KEY,
    libelle VARCHAR(255) NOT NULL,
    categorie VARCHAR(100) NOT NULL,
    mots_cles TEXT,
    exemples TEXT,
    sens CHAR(1) NOT NULL CHECK (sens IN ('D', 'C')),
    pcg_parent VARCHAR(10),
    created_at TIMESTAMP NOT NULL DEFAULT now(),
    updated_at TIMESTAMP NOT NULL DEFAULT now()
);

CREATE INDEX idx_plan_simplifie_categorie ON plan_comptable_simplifie(categorie);
CREATE INDEX idx_plan_simplifie_sens ON plan_comptable_simplifie(sens);

ALTER TABLE entreprises
    ADD COLUMN plan_comptable VARCHAR(20) NOT NULL DEFAULT 'simplifie'
        CHECK (plan_comptable IN ('general', 'simplifie'));

